  const tipParts = []
  tipParts.push(\`<strong style=\"color:var(--gold)\">\${escapeHtml(job.name || job.id || '')}</strong>\`)
  if (job.description) tipParts.push(escapeHtml(job.description))
  if (job.schedule && job.schedule.display) {
